-- Quest: ForjaPerdida
local quest = Quest("ForjaPerdida")
quest:setDescricao("No reino de Eridanus, um mistério envolve um famoso Cristal que é considerado uma das maiores riquezas mágicas jamais encontradas. Recentemente, o LordeDasSombras foi visto por perto deste cristal, o que desperta a curiosidade dos habitantes da cidade de Eridanus. O NPC sabio DeEridanus tem conhecimento profundo sobre a história e localização do Cristal.")
quest:addObjetivo("Encontrar e proteger o Cristal Sagrado antes que qualquer outro se apresse em obter seus poderes, para evitar conflitos e garantir sua segurança.")
quest:addRecompensa("xp", 5000)
print("Quest ForjaPerdida carregada.")